{
  "summary": "This paper proposes Multiple Choice Prompting (MCP), a novel approach for multiple choice question answering (MCQA) with large language models that jointly presents all answer options bound to symbols, enabling explicit comparison and reducing computational cost. Evaluated on 20 diverse datasets, MCP with models exhibiting strong Multiple Choice Symbol Binding (MCSB) ability, such as Codex, significantly outperforms traditional cloze prompting and approaches or surpasses state-of-the-art results without task-specific tuning.",
  "strengths": [
    {
      "point": "Comprehensive empirical evaluation across 20 diverse MCQA datasets",
      "evidence": "MCP consistently outperforms cloze prompting on 16 datasets with an average accuracy gain of 9.7 percentage points, surpassing prior SOTA on 9 datasets."
    },
    {
      "point": "Identification and formalization of Multiple Choice Symbol Binding (MCSB) as a key factor",
      "evidence": "The paper shows that models fine-tuned on code or instruction-following (e.g., Codex) have higher MCSB ability, which correlates with MCP effectiveness."
    },
    {
      "point": "Reduction in computational cost by requiring only one forward pass per question",
      "evidence": "MCP outputs a symbol corresponding to the chosen answer, avoiding multiple forward passes needed in cloze prompting."
    },
    {
      "point": "Clear motivation addressing limitations of cloze prompting",
      "evidence": "The paper articulates issues with cloze prompting such as conflating answer likelihood with correctness and normalization sensitivity."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to other recent prompting paradigms",
      "evidence": "The paper does not compare MCP against chain-of-thought or rationale-augmented prompting methods that have improved MCQA performance."
    },
    {
      "point": "Insufficient ablation and analysis of symbol binding variants",
      "evidence": "No experiments explore different symbol binding schemes or dataset-specific adaptations despite observed performance drops on some datasets."
    },
    {
      "point": "Potential dataset leakage not rigorously analyzed",
      "evidence": "While noting Codex’s training data, the paper does not thoroughly investigate whether MCQA datasets appear in training corpora, leaving memorization effects unaddressed."
    },
    {
      "point": "Evaluation limited to accuracy without statistical significance or additional metrics",
      "evidence": "No confidence intervals, significance testing, or metrics like calibration or robustness are reported."
    },
    {
      "point": "Baselines may be under-optimized due to lack of prompt engineering",
      "evidence": "The cloze prompting baseline is intentionally kept simple, potentially exaggerating MCP’s relative gains."
    },
    {
      "point": "Reproducibility hindered by missing prompt templates and decoding details",
      "evidence": "The paper omits explicit prompt templates and decoding parameters such as temperature or sampling methods."
    },
    {
      "point": "Limited discussion on scalability and handling of multi-answer or partial credit scenarios",
      "evidence": "No analysis on MCP’s performance with large answer sets or questions with multiple correct answers."
    },
    {
      "point": "Limited model diversity and task generalizability",
      "evidence": "Experiments focus mainly on Codex and a few LLMs, without evaluation on open-source or multilingual models or non-MCQA tasks."
    },
    {
      "point": "Clarity issues in metric definitions and computational cost claims",
      "evidence": "The Proportion of Plurality Agreement (PPA) metric lacks a clear formal definition, and computational cost reductions are not quantified."
    }
  ],
  "questions": [
    {
      "question": "How does MCP compare to other advanced prompting techniques like chain-of-thought or rationale-augmented prompting on MCQA tasks?",
      "motivation": "Understanding whether MCP’s gains are unique or complementary would clarify its relative contribution."
    },
    {
      "question": "Can MCP and MCSB be adapted or optimized per dataset, especially for datasets with short or cloze-friendly answers where MCP underperforms?",
      "motivation": "Dataset-specific tuning might improve MCP’s robustness and generalizability."
    },
    {
      "question": "What is the impact of different symbol binding schemes on MCP performance and is MCSB a generalizable property across symbol types?",
      "motivation": "Ablations could inform best practices for prompt design and model selection."
    },
    {
      "question": "To what extent do dataset leakage or memorization effects contribute to MCP’s observed gains?",
      "motivation": "Ruling out memorization is critical for assessing true generalization."
    },
    {
      "question": "How does MCP perform on MCQA tasks with large numbers of answer options or multi-answer questions?",
      "motivation": "Scalability and applicability to diverse real-world MCQA scenarios are important for practical use."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
